<script lang="ts">import Button from '../primitives/Button.svelte';export interface DecisionChoice{label:string;description?:string;effects?:string;disabled?:boolean;action:Record<string,unknown>}let {title,choices,onchoose}:{title:string;choices:readonly DecisionChoice[];onchoose:(action:Record<string,unknown>)=>void}=$props();</script>
<section><h3>{title}</h3><div class="choices">{#each choices as choice}<div class="choice"><Button variant="secondary" disabled={choice.disabled??false} onclick={()=>onchoose(choice.action)}>{choice.label}</Button>{#if choice.description}<p>{choice.description}</p>{/if}{#if choice.effects}<small>{choice.effects}</small>{/if}</div>{/each}</div></section>
<style>section{padding:var(--space-3);border:1px solid var(--color-accent);border-radius:var(--radius-lg);background:var(--color-inset)}h3{margin:0 0 var(--space-3)}.choices{display:grid;gap:var(--space-3)}.choice{display:grid;grid-template-columns:minmax(8rem,auto) 1fr;gap:var(--space-1) var(--space-3);align-items:center}.choice p,.choice small{margin:0}.choice small{grid-column:2;color:var(--color-muted)}@media(max-width:600px){.choice{grid-template-columns:1fr}.choice small{grid-column:1}}</style>
